import request from '@/utils/request'

// 档案数据管理
const profile = {
  // 获取完整档案数据
  getData() {
    console.log('获取完整档案数据')
    return request.get('/api/v1/users/profile/data/')
  },

  // 获取简历完整度（保留特殊接口）
  getCompleteness() {
    console.log('获取简历完整度')
    return request.get('/api/v1/users/profile/completeness/')
      .then(response => {
        console.log('Completeness API response:', response)
        return response
      })
  },

  // 更新模块数据
  updateModule(type, data) {
    console.log('更新模块数据:', { type, data })
    return request({
      url: `/api/v1/users/profile/${type}/`,
      method: 'put',
      data
    })
  },

  // 添加模块项目
  addModuleItem(type, data) {
    console.log('添加模块项目:', { type, data })

    // 数据预处理（保留必要的数据验证）
    let processedData = { ...data }
    if (type === 'skill') {
      processedData = {
        name: data.name?.trim() || '',
        level: data.level || '初级',
        description: data.description?.trim() || ''
      }

      if (!processedData.name) {
        throw new Error('技能名称不能为空')
      }
      if (processedData.name.length > 50) {
        throw new Error('技能名称不能超过50个字符')
      }
      if (!['初级', '中级', '高级', '专家'].includes(processedData.level)) {
        throw new Error('无效的技能等级')
      }
    }

    return request({
      url: `/api/v1/users/profile/${type}/`,
      method: 'post',
      data: processedData
    }).catch(error => {
      console.error('添加失败详情:', {
        type,
        data: processedData,
        error: error.response?.data || error
      })
      throw error
    })
  },

  // 删除模块项目
  deleteModuleItem(type, id) {
    console.log('删除模块项目:', { type, id })
    return request({
      url: `/api/v1/users/profile/${type}/${id}/`,
      method: 'delete'
    })
  },

  // 上传头像（保留特殊接口）
  uploadAvatar(formData) {
    console.log('上传头像')
    return request({
      url: '/api/v1/users/profile/avatar/upload/',
      method: 'post',
      headers: {
        'Content-Type': 'multipart/form-data'
      },
      data: formData
    })
  },

  // 获取布局配置（保留特殊接口）
  getLayout() {
    console.log('获取布局配置')
    return request.get('/api/v1/users/profile/layout/')
  },

  // 更新布局配置（保留特殊接口）
  updateLayout(data) {
    console.log('更新布局配置:', data)
    return request({
      url: '/api/v1/users/profile/layout/',
      method: 'put',
      data
    })
  },

  uploadBackground(formData) {
    return request({
      url: '/api/v1/users/profile/background/upload/',
      method: 'post',
      data: formData,
      headers: {
        'Content-Type': 'multipart/form-data'
      }
    })
  }
}

export default profile
